(function(win, doc) {
  var el = function(element) {
      if (!element) {
        element = doc
      }
      return element
    };
  var isString = function(element) {
      return typeof element === "string"
    };
  var isNull = function(element) {
      return typeof element === "null"
    };
  var hookAddLister = function(el, eventType, handler, isbool) {
      isbool = isbool || false;
      if (el.addEventListener) {
        el.addEventListener(eventType, handler, isbool)
      }
    };
  var addLister = function(domnode, eventType, handler, isbool) {
      if (el().all) {
        domnode.attachEvent("on" + eventType, handler)
      }
      hookAddLister(domnode, eventType, handler, isbool)
    };
  var trySelector = function(element) {
      if (!isString(element)) {
        return false
      }
      return el().querySelector(element)
    };
  var isIn = function(options, arr_obj) {
      var arr = [];
      if (options in arr_obj) {
        arr.push(options)
      }
      return arr
    };
  var extend = function(options, target) {
      for (var key in target) {
        options[key] = target[key]
      }
      return options
    };
  var event_set = function(option, evt) {
      var self = this;
      if (evt) {
        this.my_event = evt
      } else {
        console.log('first onload function')
      };
      if (this) {
        this.MY_EVENT = self.my_event
      };
      return this
    };
  var getter_event = {
    fun: function() {
      var alise = getter_event;
      return event_set(alise)
    }
  };
  var myself_move = function() {
      var success_get_obj = getter_event.fun(),
        success_proto_event = success_get_obj.MY_EVENT,
        arr = [];
      console.log(success_proto_event);
      [success_proto_event].forEach(function(that, index) {
        arr.push(that.frame_node)
      });
      return arr
    };
  var jumpFishing = function() {
      this.control_times = null;
      this.defined_times = null;
      this.count = null;
      this.world = {}
    };
  jumpFishing.prototype = {
    request_handle: function(parame, callback) {
      var save_object = extend(this.world, parame);
      html_element(callback);
      return this.set(save_object)
    },
    set: function(para) {
      var paramer = para;
      this.Element = paramer.parentElement;
      this.Node = paramer.eventElement;
      this.Txt_node = paramer.textNode;
      this.Events = paramer.events || "click";
      this.Text = paramer.text || "加载中...";
      this.Bk = paramer.block || "block";
      this.showdow_Time = paramer.timeout || 2000;
      paramer.Bg === undefined ? this.Bg = "rgba(0,0,0,.3)" : this.bg = paramer.Bg;
      console.log(this);
      this.reture_res_handle.call(this.set, this)
    },
    reture_res_handle: function(inhirt) {
      var ACCESS_EVENT = [],
        Event_dom, EVENTS, frame_node;
      EVENTS = {
        touchstart: 'touchstart',
        click: 'onclick',
        dragstart: 'ondragstart',
        drag: "ondrag",
        drop: 'ondrop'
      };
      frame_node_dom = {
        frame_node: inhirt.Element
      };
      ACCESS_EVENT = isIn(inhirt.Events, EVENTS);
      var self = jumpFishing.prototype;
      if (isString(inhirt.Node)) {
        Event_dom = trySelector(inhirt.Node);
        addLister(Event_dom, ACCESS_EVENT[0], function(e) {
          self.showLoading(inhirt, ACCESS_EVENT)
        })
      }
      return event_set(inhirt, frame_node_dom)
    },
    showLoading: function(para, events) {
      this.default_stop_listener(events);
      this.add_style(para);
      this.add_txt(para);
      this.deference_operation(para, events)
    },
    deference_operation: function(para, events) {
      var that = this;
      if (this.defined_times === 1) {
        var nums = addLister(trySelector(para.Element), events[0], function(e) {
          return (para.control_times = 0) &
          function() {
            that.dis_visibility()
          }()
        })
      }
      para.control_times = 1;
      this.set_time(para)
    },
    default_stop_listener: function(events) {
      return function() {
        addLister(trySelector(this.Element), events[0], function(e) {
          e.preventDefault()
        })
      }()
    },
    add_style: function(para) {
      this.dis_visibility(para.Bk);
      this.defined_times = 1
    },
    add_txt: function(para) {
      var t = para.Text;
      return t !== undefined && (trySelector(para.Txt_node).textContent = t)
    },
    set_time: function(para) {
      var that = this;
      if (para.control_times ? 1 : 0) {
        this.clear_timeout(this.count);
        this.count = setTimeout(function() {
          that.dis_visibility();
          this.defined_times = null
        }, para.showdow_Time)
      }
    },
    dis_visibility: function(_show_hide) {
      var get_frame_node = myself_move();
      _show_hide = _show_hide ? _show_hide : "none";
      trySelector(get_frame_node[0]).style.display = _show_hide
    },
    clear_timeout: function(options) {
      if (options !== null) {
        clearTimeout(options)
      }
    }
  };
  var createE = function(elements, options) {};
  var html_element = function(cabak) {
      if (cabak) {
        cabak(createE)
      }
    };
  win.jumpFish = new jumpFishing()
})(window, document)